('computer-science:1-1-2-cpu-performance:match:eececb40', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bigger cache size”?", "options": ["A CPU with two cores, able to execute two instructions at the same time", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM", "A processing unit that can run its own fetch–execute cycle", "Faster read/write speeds than a hard disk drive, so programs load quicker"]}'::jsonb, '{"answer": 1, "explain": "“Bigger cache size” means: More frequently used instructions held close to the CPU, so fewer slow trips to RAM"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:27321ddc', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Core”?", "options": ["More frequently used instructions held close to the CPU, so fewer slow trips to RAM", "Billions of fetch–execute cycles per second", "Small, very fast memory inside the CPU holding frequently used instructions and data", "A processing unit that can run its own fetch–execute cycle"]}'::jsonb, '{"answer": 3, "explain": "“Core” means: A processing unit that can run its own fetch–execute cycle"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:2d1ae9f3', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dual core”?", "options": ["Non-volatile memory holding the boot-up instructions (BIOS)", "A CPU with two cores, able to execute two instructions at the same time", "Volatile memory holding the programs and data currently running", "A processing unit that can run its own fetch–execute cycle"]}'::jsonb, '{"answer": 1, "explain": "“Dual core” means: A CPU with two cores, able to execute two instructions at the same time"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:f6670354', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Parallel processing”?", "options": ["Billions of fetch–execute cycles per second", "A CPU with two cores, able to execute two instructions at the same time", "Several cores each executing a separate instruction simultaneously", "Space on secondary storage used as overflow when RAM is full — much slower to access"]}'::jsonb, '{"answer": 2, "explain": "“Parallel processing” means: Several cores each executing a separate instruction simultaneously"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:a8d8ca57', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multitasking”?", "options": ["Running more than one program at once, made smoother by extra cores", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM", "Non-volatile memory holding the boot-up instructions (BIOS)", "Volatile memory holding the programs and data currently running"]}'::jsonb, '{"answer": 0, "explain": "“Multitasking” means: Running more than one program at once, made smoother by extra cores"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:dd37f250', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Why more cores isn''t always faster”?", "options": ["Some tasks cannot be split, and software must be written to use them", "The number of fetch–execute cycles the CPU carries out per second", "Several cores each executing a separate instruction simultaneously", "Small, very fast memory inside the CPU holding frequently used instructions and data"]}'::jsonb, '{"answer": 0, "explain": "“Why more cores isn''t always faster” means: Some tasks cannot be split, and software must be written to use them"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:482c2ab9', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “RAM”?", "options": ["Several cores each executing a separate instruction simultaneously", "Volatile memory holding the programs and data currently running", "Running more than one program at once, made smoother by extra cores", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM"]}'::jsonb, '{"answer": 1, "explain": "“RAM” means: Volatile memory holding the programs and data currently running"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:a74ea477', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “ROM”?", "options": ["Some tasks cannot be split, and software must be written to use them", "The unit of clock speed — one cycle per second", "Non-volatile memory holding the boot-up instructions (BIOS)", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM"]}'::jsonb, '{"answer": 2, "explain": "“ROM” means: Non-volatile memory holding the boot-up instructions (BIOS)"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:885d0ceb', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Virtual memory”?", "options": ["Some tasks cannot be split, and software must be written to use them", "The number of fetch–execute cycles the CPU carries out per second", "Space on secondary storage used as overflow when RAM is full — much slower to access", "Volatile memory holding the programs and data currently running"]}'::jsonb, '{"answer": 2, "explain": "“Virtual memory” means: Space on secondary storage used as overflow when RAM is full — much slower to access"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:27b5d052', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Upgrading to an SSD”?", "options": ["More frequently used instructions held close to the CPU, so fewer slow trips to RAM", "Running more than one program at once, made smoother by extra cores", "Faster read/write speeds than a hard disk drive, so programs load quicker", "Some tasks cannot be split, and software must be written to use them"]}'::jsonb, '{"answer": 2, "explain": "“Upgrading to an SSD” means: Faster read/write speeds than a hard disk drive, so programs load quicker"}'::jsonb),
('computer-science:1-1-3-embedded-systems:exam:70ac4718', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'exam', 'mcq', 1, '{"num": "Q5(i)", "question": "<p>Xander''s tablet computer comes with system software, including an operating system and utility system software.</p><p>Xander also has a smart watch.</p><p>Tick (✓) <strong>one</strong> box to show whether the smart watch or the laptop is an example of an embedded system.</p>", "options": ["Smart watch", "Laptop"], "hint": "Which of the two can only ever do its own small set of jobs?"}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2 1a)</h5>\n<ul>\n<li><strong>Smart watch</strong> — CAO (correct answer only)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>This question was answered correctly by the majority of candidates who were able to identify that a smart watch is an example of an embedded system.</p>\n</div>", "modelAnswer": "Smart watch"}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:7cbb9001', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Which best defines an embedded system?", "options": ["Any computer that has no physical keyboard attached to it at all", "A computer system built into a larger device to perform one specific task", "A computer that runs on rechargeable batteries instead of mains electricity", "A very small laptop with a stripped-down operating system already installed"]}'::jsonb, '{"answer": 1, "explain": "Two halves: built INTO a larger device, and dedicated to one specific (or limited) task. Size, batteries and keyboards are irrelevant."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:6c3520ff', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Which of these is an embedded system?", "options": ["A desktop PC with a full operating system used for browsing and office work", "A laptop with a full operating system used for work and browsing", "A washing machine that runs one fixed wash programme automatically", "A tablet with a touchscreen used for apps, browsing and video streaming"]}'::jsonb, '{"answer": 2, "explain": "The washing machine''s computer does one job forever. The other three are general-purpose computers you can install any software on."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:af3e37d8', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Why is a laptop NOT an embedded system?", "options": ["It is too expensive for an average household budget to justify", "It is general purpose — you can install any software you like", "It has a microprocessor, since every modern computer needs one", "It uses an operating system that loads fresh each time it boots"]}'::jsonb, '{"answer": 1, "explain": "General purpose is the opposite of embedded. Having a microprocessor or an OS doesn''t decide it — embedded systems have those too."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:841f262e', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "An embedded system''s program is usually stored as firmware in ROM. What does this mean in practice?", "options": ["The user can install and remove new apps whenever they like", "The instructions are fixed and normally cannot be changed by the user", "The program is deleted permanently every time the power is switched off", "The system needs a hard drive to store its operating system"]}'::jsonb, '{"answer": 1, "explain": "Firmware in ROM is permanent and non-volatile — it starts instantly and the user doesn''t update or replace it. That''s why there''s no app store on your dishwasher."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:d602c780', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Which phrase would actually earn a mark when describing an embedded system?", "options": ["It has a microprocessor, just like any general-purpose computer", "It has a dedicated microprocessor doing only this job", "It is electronic and needs a power supply to work", "It has a circuit board holding its electronic components"]}'::jsonb, '{"answer": 1, "explain": "Every computer has a microprocessor, so that fact distinguishes nothing. ''Dedicated'' is the word that carries the meaning."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:8fa64734', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "A question asks for an embedded system found in a car. Which answer earns the mark?", "options": ["A microwave used to heat food in the kitchen", "A washing machine used to wash clothes at home", "The anti-lock braking system fitted to the car", "A games console used to play video games at home"]}'::jsonb, '{"answer": 2, "explain": "Read the context. The first two ARE embedded systems, but they''re not in a car — candidates lost this exact mark in the real exam."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:4a7e28e3', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Ali says his tablet is an embedded system. Which reason shows he is incorrect?", "options": ["Tablets have touchscreens, and touchscreens are only found on embedded systems", "A tablet has multiple functions and is general purpose, unlike an embedded system", "Tablets are portable, and only embedded systems are designed to be portable", "Tablets use rechargeable batteries, whereas embedded systems always run on mains power only"]}'::jsonb, '{"answer": 1, "explain": "The deciding characteristic is purpose: an embedded system does one dedicated job; a tablet does anything you install on it."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:24b24605', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Which statement is TRUE about a smartphone?", "options": ["It is an embedded system, since it only runs the apps that come pre-installed on it", "It is general purpose, but it contains embedded systems inside it", "It contains no embedded systems at all, only general-purpose software", "It is firmware — permanent software stored directly in its ROM chip"]}'::jsonb, '{"answer": 1, "explain": "A neat distinction: the phone itself is a general-purpose computer, but components inside it (battery management, camera stabilisation) are embedded systems."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:1ea36468', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Why is a smart watch classed as an embedded system?", "options": ["It is small enough to be worn comfortably on your wrist all day", "It is not a general-purpose computer — it has limited, dedicated functions", "It connects to a phone over Bluetooth to sync data, notifications and health tracking", "It has a touchscreen you can tap and swipe to interact with it"]}'::jsonb, '{"answer": 1, "explain": "Limited, dedicated function is the reason. Size, touchscreens and connectivity say nothing about whether something is embedded."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:869d5946', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "Which is a typical characteristic of an embedded system?", "options": ["It can be expanded with new hardware whenever the user wants", "It has few components, all essential to its purpose", "It runs any software the user installs", "It always has a large screen"]}'::jsonb, '{"answer": 1, "explain": "Embedded systems are built with only what the one job needs — few components, dedicated hardware, limited functions."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:fbd3859a', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "A cruise control system keeps a car at a set distance from the car in front, with no driver input. Which characteristic does this best show?", "options": ["It is general purpose, so it could be reprogrammed to do any task", "It is an automated control system with a specific purpose", "It can run any software the driver chooses to install on it", "It has a large amount of storage for the driver''s personal files"]}'::jsonb, '{"answer": 1, "explain": "It senses something and responds automatically without the user — an automated control system dedicated to that one task."}'::jsonb),
('computer-science:1-1-3-embedded-systems:mcq:dc07aa4b', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'mcq', 'mcq', 1, '{"question": "A 3-mark question asks you to explain why a system is embedded. What should your answer contain?", "options": ["One very detailed point about the system''s single specific purpose", "Three separate characteristics of embedded systems, each applied to the scenario", "A definition copied word-for-word from the textbook, with no reference to the scenario at all", "A list of other embedded systems found in similar everyday devices"]}'::jsonb, '{"answer": 1, "explain": "Three marks means three distinct points — and each must be applied to the scenario. Real candidates commonly gave one point and stopped."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:3897bfac', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "An embedded system is any computer that is physically small."}'::jsonb, '{"answer": false, "explain": "Size has nothing to do with it. An engine management system is powerful and complex, but it''s embedded because it''s dedicated to one job inside a larger machine."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:a0e31797', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "A washing machine contains an embedded system."}'::jsonb, '{"answer": true, "explain": "Correct — a computer built into the machine, doing exactly one job: running the wash programme you selected."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:80d3ab55', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "A tablet computer is an embedded system because it has a microprocessor and an operating system."}'::jsonb, '{"answer": false, "explain": "Both are true of tablets, and neither makes something embedded. A tablet is self-contained, general purpose, and you can install whatever you like on it."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:bb1624f2', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "The software in an embedded system is usually firmware stored in ROM."}'::jsonb, '{"answer": true, "explain": "Yes — fixed, non-volatile, instant to start, and normally not changeable by the user. It''s why you can''t install apps on a microwave."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:f1103f28', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "A smartphone is a general-purpose computer, but it contains embedded systems inside it."}'::jsonb, '{"answer": true, "explain": "A neat distinction worth knowing: the phone itself runs anything you install, but its battery-management and camera-stabilisation chips are dedicated embedded systems."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:15be2790', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "Writing ''an embedded system has limited functions'' is enough to justify why a smart watch is embedded."}'::jsonb, '{"answer": false, "explain": "That''s a generic definition, and the mark scheme explicitly refuses those on justify questions. Apply it: ''…and the smart watch only tracks time, steps and heart rate''."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:ae75d7b9', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "If a question says a system is ''built into the car'', you can earn a mark by saying it is built into the car."}'::jsonb, '{"answer": false, "explain": "That point is already in the question, so it shows no knowledge of your own — it is explicitly not awarded. Use a different characteristic instead."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tf:3f51843b', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tf', 'tf', 1, '{"question": "Embedded systems are often control systems that respond automatically without the user."}'::jsonb, '{"answer": true, "explain": "True — automatic headlights sense the light level and switch on by themselves; cruise control maintains speed and distance with no driver input."}'::jsonb),
('computer-science:1-1-3-embedded-systems:learn:177f479e', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'learn', 'mcq', 1, '{"readingTitle": "What is an embedded system?", "reading": "<h4>The definition to learn word-for-word</h4>\n<ul>\n<li><strong>An embedded system is a computer system built into a larger device, dedicated to carrying out one specific task (or a small, limited set of tasks).</strong></li>\n<li>That single sentence has both halves examiners look for: it is <strong>built into</strong> something else, and it has <strong>one specific purpose</strong>.</li>\n<li>The washing machine on your kitchen floor contains a computer. You never think of it as a computer, because it only ever does one job — that''s exactly what makes it embedded.</li>\n</ul>\n<h4>Embedded doesn''t mean small or simple</h4>\n<ul>\n<li>An engine management system in a car is doing extraordinary work thousands of times a second. It''s still embedded, because it is <em>dedicated</em> to that one job inside a larger machine.</li>\n<li>The opposite of \"embedded\" is not \"big\" — it''s <strong>general purpose</strong>. A laptop is general purpose because you can install anything on it and make it do almost any task.</li>\n</ul>\n<h4>The word \"dedicated\"</h4>\n<ul>\n<li>You''ll see this word all over the mark schemes: <strong>dedicated hardware</strong>, <strong>dedicated microprocessor</strong>, <strong>dedicated to one function</strong>.</li>\n<li>It means \"reserved for this one job and nothing else\". The microprocessor inside a set of automatic headlights does nothing but check the light level and switch the lights — it will never run a spreadsheet.</li>\n</ul>", "question": "Which is the best definition of an embedded system?", "options": ["Any general-purpose computer that happens to be physically small", "A computer system built into a larger device to perform one specific task", "A computer system that has no screen or keyboard connected to it", "A computer that cannot connect to the internet or download any new software updates"]}'::jsonb, '{"answer": 1, "explain": "Both halves matter: built INTO a larger device, and dedicated to one specific (or limited) task. Size and screens have nothing to do with it — an engine management system is powerful, and plenty of general-purpose computers are small."}'::jsonb),
('computer-science:1-1-3-embedded-systems:learn:ec5f7bd8', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'learn', 'mcq', 1, '{"readingTitle": "The characteristics of an embedded system", "reading": "<h4>The list that earns the marks</h4>\n<ul>\n<li><strong>One specific purpose</strong> — it performs a single task, or only a few limited functions.</li>\n<li><strong>Built into a larger device</strong> — it is part of a bigger machine, not a machine in its own right.</li>\n<li><strong>Dedicated hardware</strong> — its own microprocessor and sensors, used only for this system.</li>\n<li><strong>Hard to change</strong> — the program is usually stored in ROM as <strong>firmware</strong>, so it isn''t updated or replaced the way you install apps on a phone.</li>\n<li><strong>Often a control system</strong> — it senses something and responds automatically, without the user telling it to.</li>\n<li><strong>Few components</strong>, all essential to its purpose; typically small, cheap and low-power.</li>\n</ul>\n<h4>Why \"it has a microprocessor\" alone isn''t worth much</h4>\n<ul>\n<li>Every computer has a microprocessor — so that fact doesn''t distinguish anything. The creditworthy version is <strong>\"it has a <em>dedicated</em> microprocessor\"</strong>, i.e. one doing only this job.</li>\n</ul>\n<h4>Firmware — the reason your washing machine has no app store</h4>\n<ul>\n<li><strong>Firmware</strong> is software stored permanently in ROM. It boots instantly, never gets deleted, and normally cannot be changed by the user.</li>\n<li>That''s why you can''t install a game on your dishwasher: its instructions are fixed in hardware-level storage, not loaded from a disk like on a general-purpose computer.</li>\n</ul>", "question": "Which statement about an embedded system''s software is correct?", "options": ["Users install and update apps on it freely, just like on a phone", "Its program is usually firmware stored in ROM and is hard to change", "It has no software at all, only electronic circuits and wires", "It downloads and installs a brand new operating system every time it starts"]}'::jsonb, '{"answer": 1, "explain": "Embedded systems normally run firmware held in ROM — fixed, instant to start, and not something the user updates or replaces."}'::jsonb),
('computer-science:1-1-3-embedded-systems:learn:94beb044', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'learn', 'mcq', 1, '{"readingTitle": "Embedded vs general purpose — the question they always ask", "reading": "<h4>The test to apply</h4>\n<ul>\n<li>Ask yourself: <strong>\"Can I install whatever I like on it and make it do a completely different job?\"</strong></li>\n<li><strong>Yes</strong> → it''s a <strong>general-purpose</strong> computer (laptop, desktop, tablet, smartphone).</li>\n<li><strong>No — it does its one job forever</strong> → it''s an <strong>embedded system</strong> (smart watch, washing machine, sat nav, microwave).</li>\n</ul>\n<h4>Worked comparison: smart watch vs laptop</h4>\n<ul>\n<li><strong>Smart watch = embedded.</strong> It is not a general-purpose computer: it has limited, dedicated functions; a microprocessor on a single circuit board; a built-in OS that you cannot really change; and few components, all essential to its purpose.</li>\n<li><strong>Laptop = general purpose.</strong> You can install any software you like and use it for any number of tasks; its hardware can be expanded; its OS can be updated or even replaced.</li>\n</ul>\n<h4>Is a tablet an embedded system? (No — and here''s the reasoning)</h4>\n<ul>\n<li>A tablet has <strong>multiple functions</strong> and is <strong>general purpose</strong>; an embedded system has one or few.</li>\n<li>A tablet is a <strong>self-contained system</strong>, not part of a larger machine.</li>\n<li>You can <strong>update or install software</strong> on a tablet freely.</li>\n</ul>\n<h4>The nuance that impresses: a phone <em>contains</em> embedded systems</h4>\n<ul>\n<li>A smartphone is a <strong>general-purpose computer</strong> — but the camera-stabilising module and the battery-management chip inside it <em>are</em> embedded systems.</li>\n<li>So the question \"is this device an embedded system?\" is different from \"does this device contain embedded systems?\". Read the question carefully.</li>\n</ul>", "question": "Why is a tablet NOT an embedded system?", "options": ["It is too small to contain a full operating system, storage chip or microprocessor", "It is general purpose — it has many functions and you can install new software", "It has a microprocessor, exactly like every embedded system does", "It uses electricity, exactly like every embedded system does too"]}'::jsonb, '{"answer": 1, "explain": "Embedded systems do one dedicated job inside a larger device and can''t easily be repurposed. A tablet is a self-contained, general-purpose computer you can install anything on."}'::jsonb),
('computer-science:1-1-3-embedded-systems:learn:be194509', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'learn', 'mcq', 1, '{"readingTitle": "A range of examples (the spec wants breadth)", "reading": "<h4>Around the house</h4>\n<ul>\n<li><strong>Washing machine</strong> — runs the chosen programme: fill, wash, spin, drain.</li>\n<li><strong>Microwave, dishwasher, fridge/freezer, oven</strong> — each with one job and a control panel.</li>\n<li><strong>Central heating thermostat</strong> — senses temperature, switches the boiler.</li>\n<li><strong>TV remote, printer, digital camera, MP3 player.</strong></li>\n</ul>\n<h4>Inside a car (a favourite exam context)</h4>\n<ul>\n<li><strong>Engine management system</strong>, <strong>anti-lock brakes</strong>, <strong>parking sensors</strong>, <strong>cruise control</strong> (including \"follow me\" adaptive systems), <strong>automatic lights</strong>, <strong>automatic windscreen wipers</strong>, <strong>climate control</strong>, <strong>sat nav / GPS</strong>, <strong>lane assist</strong>, <strong>auto-park</strong>, <strong>dashcam</strong>.</li>\n<li><strong>Watch the context.</strong> If the question says \"in a car\", answering \"a washing machine\" scores nothing — real candidates lost marks doing exactly that.</li>\n</ul>\n<h4>Worn, medical and industrial</h4>\n<ul>\n<li><strong>Smart watch</strong>, <strong>fitness tracker</strong>, <strong>pacemaker</strong>, <strong>insulin pump</strong>.</li>\n<li><strong>Traffic lights</strong>, <strong>manufacturing/robotic equipment</strong>, <strong>vending machines</strong>, <strong>ticket machines</strong>, <strong>lifts</strong>, <strong>security alarms</strong>.</li>\n</ul>\n<h4>Learn three you can always reach for</h4>\n<ul>\n<li>Keep a reliable trio in your head — <strong>washing machine, sat nav, traffic lights</strong> — for any \"identify three devices containing embedded systems\" question. Then swap them for context-appropriate ones when the question sets a scene.</li>\n</ul>", "question": "A question asks you to identify an embedded system found in a CAR. Which answer earns the mark?", "options": ["A washing machine used to wash clothes at home", "A microwave used to heat and cook food", "The engine management system fitted inside the car", "A desktop computer used for browsing and general office work"]}'::jsonb, '{"answer": 2, "explain": "The context is the car. Washing machines and microwaves are embedded systems, but they''re not in a car — candidates genuinely lost this mark by ignoring the scenario."}'::jsonb),
('computer-science:1-1-3-embedded-systems:learn:98bc1df8', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'learn', 'mcq', 1, '{"readingTitle": "How to answer: apply it, don''t define it", "reading": "<h4>The single biggest mark-loser on this topic</h4>\n<ul>\n<li>Questions here almost always give you a <strong>scenario</strong> — Ali''s tablet, Xander''s smart watch, the car''s ''Follow Me'' system — and ask you to <strong>justify</strong> or <strong>explain</strong>.</li>\n<li>Writing a textbook definition of an embedded system earns <strong>nothing</strong>. The mark scheme is explicit: <em>answers must be applied to the scenario; do not award generic definitions.</em></li>\n</ul>\n<h4>The two-part sentence that always works</h4>\n<ul>\n<li><strong>Feature → applied to this device.</strong></li>\n<li>❌ Generic: \"An embedded system has limited functions.\"</li>\n<li>✅ Applied: \"An embedded system has limited functions, <strong>and the smart watch</strong> only tracks time, steps and heart rate — it cannot be used for any task you like.\"</li>\n<li>Same feature. The second one scores.</li>\n</ul>\n<h4>Don''t hand back the question</h4>\n<ul>\n<li>If the question already tells you the system is \"built into the car\", you cannot earn a mark by saying \"it is built into the car\". That point is <strong>in the question</strong>, so it shows no knowledge of your own.</li>\n<li>Reach for a different characteristic instead: dedicated microprocessor, limited functions, firmware that can''t be changed.</li>\n</ul>\n<h4>Count the marks, make that many points</h4>\n<ul>\n<li>A 3-mark \"explain why this is an embedded system\" wants <strong>three separate characteristics</strong>. Many candidates give one good point and stop — which caps them at 1.</li>\n<li>Have the list ready: specific purpose · built into a larger device · dedicated hardware/microprocessor · firmware, hard to change · automated control system.</li>\n</ul>", "question": "A 2-mark question asks you to justify why a smart watch is an embedded system. Which answer scores?", "options": ["An embedded system is a computer system that is built into a larger device and performs one specific purpose", "A smart watch is not a general-purpose computer — it has limited, dedicated functions", "Smart watches are small enough to be worn comfortably on a wrist", "It has a microprocessor, which every general-purpose computer also has"]}'::jsonb, '{"answer": 1, "explain": "Only the second applies the feature to THIS device. The first is a textbook definition — explicitly not credited on a justify question — and the last two say nothing that distinguishes an embedded system."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:f3ec46fd', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering a ''justify'' question with a textbook definition: ''An embedded system is built into a larger device and has one purpose.''</p><p><strong>✅ The correct idea:</strong> The mark scheme for these questions says it outright: <strong>answers must be applied to the scenario; do not award generic definitions.</strong> Candidates who gave a perfect definition of an embedded system scored zero, because the question asked about <em>this</em> smart watch or <em>this</em> tablet. Use the two-part sentence: <strong>feature → applied to this device.</strong> Weak: ''embedded systems have limited functions.'' Strong: ''embedded systems have limited functions, and the smart watch only tracks time, steps and heart rate — it cannot be used for any task you like.''</p>", "question": "Why does a flawless definition of an embedded system score 0 on a ''justify your choice'' question?", "options": ["Definitions are always wrong on every type of exam question", "The question needs the characteristic applied to the device in the scenario", "It is too short to cover all the required assessment objectives", "Definitions belong only in the conclusion, never at the start of an exam answer"]}'::jsonb, '{"answer": 1, "explain": "Justify and explain questions test application. The knowledge is only creditworthy once it is attached to the device in front of you."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:bc13c033', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Giving ''it is built into the car'' as a reason why a car system is embedded — when the question already told you it''s in the car.</p><p><strong>✅ The correct idea:</strong> You cannot earn marks by handing the question back. This point is <strong>in the stem</strong>, so it is explicitly not awarded — real candidates repeated it and got nothing. Reach for a characteristic the question <em>hasn''t</em> given you: it has <strong>limited functions</strong> (the system only checks the light level and switches the lights), it has a <strong>dedicated microprocessor</strong>, or its function is <strong>hard to change</strong>.</p>", "question": "The question states: ''A car comes with many embedded systems, for example parking sensors.'' Which explanation would earn a mark?", "options": ["It is built into the car, exactly as the question already states", "It is part of a larger machine, just like every embedded system is", "It has a dedicated microprocessor that only monitors the sensors", "The car contains it, along with many other embedded systems too"]}'::jsonb, '{"answer": 2, "explain": "The first, second and fourth are all just restating what the question already said. Only the dedicated-microprocessor point adds knowledge of your own."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:019bceb9', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''identify an embedded system in a car'', answering ''a washing machine'' or ''a microwave''.</p><p><strong>✅ The correct idea:</strong> These <em>are</em> embedded systems — but they are not in a car, and the examiner report notes candidates genuinely gave them and scored nothing. <strong>The context sets the answer.</strong> For a car, use: engine management, anti-lock brakes, parking sensors, cruise control, automatic lights or wipers, climate control, sat nav, lane assist. Always re-read the scenario before you pick your example.</p>", "question": "What went wrong when candidates answered ''washing machine'' to a question about embedded systems in a car?", "options": ["A washing machine is not an embedded system at all, in any context", "The answer ignored the context — it''s valid, just not an example found in a car", "Washing machines have no microprocessor or any dedicated hardware components at all", "The spelling of ''washing machine'' was wrong in the candidate''s answer"]}'::jsonb, '{"answer": 1, "explain": "The example itself is fine; it just doesn''t answer the question that was asked. Context-appropriate examples are the whole point of an applied question."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:d9d27713', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Saying ''it has a microprocessor'' as a characteristic that makes something embedded.</p><p><strong>✅ The correct idea:</strong> Every computer has a microprocessor — a laptop, a games console, a server. So the fact distinguishes nothing and adds no knowledge. The creditworthy version is <strong>''it has a <em>dedicated</em> microprocessor''</strong>, i.e. one doing only this job and nothing else — better still, prove it with an example: ''there is a microprocessor that does nothing but check the light level''.</p>", "question": "Which version of the microprocessor point is worth a mark?", "options": ["It has a microprocessor, just like every other type of computer", "It is controlled by electronics, like nearly all modern devices", "It has a dedicated microprocessor that only monitors the light level", "It contains a chip, which almost every modern electronic device also has"]}'::jsonb, '{"answer": 2, "explain": "''Dedicated'', ideally with an example of the one job it does, is what shows understanding of an embedded system."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:ae8a1808', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering a 3-mark ''explain why this is an embedded system'' with one good point, written at length.</p><p><strong>✅ The correct idea:</strong> Three marks means <strong>three separate characteristics</strong>. The examiner report is blunt: most candidates got the ''single purpose'' point, some added ''built into a larger system'', but <strong>few could produce a third</strong>. Keep the list ready and work down it: <strong>specific purpose · built into a larger device · dedicated hardware/microprocessor · firmware that is hard to change · automated control system</strong>. Three short applied sentences beat one long one every time.</p>", "question": "A 3-mark question asks why the ''Follow Me'' cruise control is an embedded system. What''s the best structure?", "options": ["One very detailed paragraph focused only on its single specific purpose", "Three different characteristics, each linked to the Follow Me system", "A definition of an embedded system copied straight from a textbook", "A list of other cars that also come fitted with cruise control"]}'::jsonb, '{"answer": 1, "explain": "One mark per characteristic, to a maximum of three — so three distinct points, each applied to the system in the question."}'::jsonb),
('computer-science:1-1-3-embedded-systems:misc:a173dd17', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking that because a smartphone runs apps, nothing inside it can be an embedded system.</p><p><strong>✅ The correct idea:</strong> Both things are true at once. The <strong>phone as a whole</strong> is a general-purpose computer — you install what you like. But <strong>inside it</strong> sit embedded systems: the battery-management chip, the camera-stabilisation module. So watch the exact wording: <em>''Is this device an embedded system?''</em> and <em>''Does this device contain embedded systems?''</em> have different answers for a phone.</p>", "question": "Which statement about a smartphone is correct?", "options": ["It is an embedded system, since every part of it does one fixed job", "It is general purpose overall, but contains embedded systems inside it", "It contains no embedded systems anywhere inside it, only general-purpose software", "It is firmware — instructions stored permanently inside a ROM chip"]}'::jsonb, '{"answer": 1, "explain": "The device itself is general purpose; specific dedicated components inside it are embedded systems. Read whether the question asks ''is'' or ''contains''."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tips:c966d276', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Justify'' and ''explain'' questions: from 0 to full marks", "reading": "<p>Nearly every question on this topic gives you a scenario and asks you to justify or explain. Here is the same answer to <em>\"Justify why the smart watch is an example of an embedded system\"</em> <strong>[2]</strong> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"An embedded system is a computer built into a larger device with one specific purpose.\"</p>\n<ul>\n<li>A textbook-perfect definition — and worth nothing. The mark scheme says: <em>answers must be applied to the scenario; do not award generic definitions.</em></li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"A smart watch is not a general-purpose computer.\"</p>\n<ul>\n<li>Applied to the device, so it scores — but it stops there. The second mark needs a development.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"A smart watch is not a general-purpose computer <strong>(1)</strong>, which means it only has limited, dedicated functions such as tracking your steps and heart rate — you cannot install any software you like on it <strong>(1)</strong>.\"</p>\n\n<p><strong>The formula:</strong> feature of an embedded system → <em>\"…and this device…\"</em> → the specific evidence from the scenario.</p>\n\n<p><strong>Bonus technique:</strong> you''re also allowed to argue the opposite way — \"a laptop <em>is</em> general purpose because you can install any software\" — as long as you don''t just repeat the same point twice in different words.</p>", "question": "You''ve written ''a smart watch is not a general-purpose computer''. What earns the second mark?", "options": ["Saying the exact same point again, just phrased in slightly different words", "Adding what its limited, dedicated functions actually are on this device", "Defining an embedded system in general, textbook terms", "Naming a completely different embedded system as an example"]}'::jsonb, '{"answer": 1, "explain": "The second mark is the development: the specific evidence from the scenario that proves your point."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tips:abfc2297', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tips', 'mcq', 1, '{"readingTitle": "tip — Counting the marks — and never repeating the question", "reading": "<p><strong>1. The tariff tells you how many points to make.</strong></p>\n<ul>\n<li><em>\"Explain the reasons why the ''Follow Me'' system is an example of an embedded system\"</em> <strong>[3]</strong> = <strong>three</strong> separate characteristics, each applied.</li>\n<li>The examiner report on this exact question: most candidates got \"single purpose\", some added \"built into the car\", but <strong>few managed a third point</strong>. That third mark is sitting there for anyone with the list memorised.</li>\n<li><strong>Your list:</strong> specific purpose · built into a larger device · dedicated hardware / microprocessor · firmware, hard to change · automated control system.</li>\n</ul>\n\n<p><strong>2. Never hand the question back.</strong></p>\n<ul>\n<li>If the stem says \"A car comes with many embedded systems…\", then <strong>\"it is built into the car\"</strong> earns nothing — that point is in the question.</li>\n<li>Cross it off your list for that question and use the next characteristic instead.</li>\n</ul>\n\n<p><strong>3. Match the example to the context.</strong></p>\n<ul>\n<li>Asked for an embedded system <strong>in a car</strong>? Engine management, ABS, parking sensors, cruise control, automatic lights or wipers, climate control, sat nav.</li>\n<li>Candidates who wrote \"washing machine\" or \"microwave\" for a car question scored zero — right idea, wrong scene.</li>\n</ul>\n\n<p><strong>4. \"Identify three devices\" = three quick words.</strong></p>\n<ul>\n<li>No explanation needed, no marks for detail — just three valid devices. Keep a reliable trio ready: <strong>washing machine, sat nav, traffic lights</strong>.</li>\n</ul>", "question": "A question says: ''Parking sensors are an embedded system in a car. Identify one other embedded system in a car and explain why.'' Which explanation is refused?", "options": ["It has a dedicated microprocessor", "It only performs one limited function", "It is built into the car", "The user cannot change what it does"]}'::jsonb, '{"answer": 2, "explain": "''Built into the car'' is stated in the question itself, so it cannot earn a mark — it shows no knowledge of your own."}'::jsonb),
('computer-science:1-1-3-embedded-systems:tips:418e448b', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'tips', 'mcq', 1, '{"readingTitle": "tip — The word-bank question: read the sentence, not just the list", "reading": "<p>This topic often gives a paragraph with gaps and a <strong>bank of terms</strong> — with the warning <em>\"Not all terms are used\"</em>. Those spare terms are deliberate traps.</p>\n\n<p><strong>How to beat it:</strong></p>\n<ul>\n<li><strong>Read the whole sentence first</strong>, then choose. \"Embedded systems have limited ……\" — <em>functions</em> fits; <em>applications</em> and <em>range</em> are plausible-looking decoys.</li>\n<li><strong>Watch the grammar.</strong> \"built into a …… machine\" needs an adjective (<em>larger</em>), not a noun (<em>laptop</em>).</li>\n<li><strong>Use each term once</strong>, and expect several to be left over. If you''ve used every word, you''ve made a mistake.</li>\n<li><strong>Do the ones you''re sure of first</strong> — eliminating terms makes the harder gaps much easier.</li>\n</ul>\n\n<p><strong>Classic decoy pairs to watch for:</strong></p>\n<ul>\n<li><em>microprocessor</em> vs <em>processor</em> — both look right; the sentence decides.</li>\n<li><em>larger</em> vs <em>smaller</em> — an embedded system is built into a <strong>larger</strong> machine.</li>\n<li><em>functions</em> vs <em>applications</em> — embedded systems have limited <strong>functions</strong>.</li>\n</ul>", "question": "In ''They are often built into a …… machine'', which term fits and why?", "options": ["laptop — it is a type of general-purpose computing machine, so the word fits grammatically", "larger — the gap needs an adjective, and embedded systems sit inside bigger devices", "smaller — embedded systems are usually physically small in size", "processor — it is simply a computer part found inside a machine"]}'::jsonb, '{"answer": 1, "explain": "Grammar plus meaning: the gap needs an adjective before ''machine'', and the whole point of embedded is being built into something LARGER."}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:55393339', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "An embedded system is a computer built into a _____ device, dedicated to one _____ task.", "blankOptions": {"B1": ["larger", "functions", "microwave", "ROM"], "B2": ["specific", "definition", "ROM", "functions"]}}'::jsonb, '{"blanks": {"B1": "larger", "B2": "specific"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:c8b09a56', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "Embedded systems have limited _____ and often use _____ hardware reserved for that one job.", "blankOptions": {"B1": ["functions", "definition", "firmware", "specific"], "B2": ["dedicated", "lights", "ROM", "specific"]}}'::jsonb, '{"blanks": {"B1": "functions", "B2": "dedicated"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:0b9c8737', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "The program of an embedded system is usually stored as _____ in _____, so the user cannot easily change it.", "blankOptions": {"B1": ["lights", "microwave", "firmware", "dedicated"], "B2": ["general", "ROM", "lights", "larger"]}}'::jsonb, '{"blanks": {"B1": "firmware", "B2": "ROM"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:d0d3c36f', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "The opposite of an embedded system is a _____ purpose computer, such as a laptop or _____.", "blankOptions": {"B1": ["general", "dedicated", "lights", "apply"], "B2": ["engine", "lights", "microwave", "tablet"]}}'::jsonb, '{"blanks": {"B1": "general", "B2": "tablet"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:4a0d65e6', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "Two household examples of embedded systems are a _____ machine and a _____.", "blankOptions": {"B1": ["tablet", "engine", "lights", "washing"], "B2": ["engine", "microwave", "tablet", "general"]}}'::jsonb, '{"blanks": {"B1": "washing", "B2": "microwave"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:9f98b0a8', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "In a car, the _____ management system and the automatic _____ are both embedded systems.", "blankOptions": {"B1": ["tablet", "ROM", "general", "engine"], "B2": ["general", "dedicated", "washing", "lights"]}}'::jsonb, '{"blanks": {"B1": "engine", "B2": "lights"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:63290626', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 1, '{"question": "Saying ''it has a microprocessor'' earns nothing — you must say it has a _____ microprocessor.", "blankOptions": {"B1": ["apply", "washing", "engine", "dedicated"]}}'::jsonb, '{"blanks": {"B1": "dedicated"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:fib:03e46dd9', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'fib', 'fib', 2, '{"question": "On a justify question you must _____ the characteristic to the device in the question — a generic _____ scores nothing.", "blankOptions": {"B1": ["apply", "lights", "specific", "washing"], "B2": ["firmware", "definition", "lights", "engine"]}}'::jsonb, '{"blanks": {"B1": "apply", "B2": "definition"}}'::jsonb),
('computer-science:1-1-3-embedded-systems:match:00d8d13e', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Embedded system”?", "options": ["General purpose overall, but contains embedded systems inside it", "A computer that can run any software and perform many different tasks", "A computer system built into a larger device to perform one specific task", "Justify questions need the characteristic applied to the device in the scenario"]}'::jsonb, '{"answer": 2, "explain": "“Embedded system” means: A computer system built into a larger device to perform one specific task"}'::jsonb),
('computer-science:1-1-3-embedded-systems:match:59601b7c', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “General-purpose computer”?", "options": ["A wearable embedded system with limited, dedicated functions", "NOT embedded — a self-contained, general-purpose computer", "Justify questions need the characteristic applied to the device in the scenario", "A computer that can run any software and perform many different tasks"]}'::jsonb, '{"answer": 3, "explain": "“General-purpose computer” means: A computer that can run any software and perform many different tasks"}'::jsonb),
('computer-science:1-1-3-embedded-systems:match:a952f93a', 'computer-science', 'computer-science:1-1-3-embedded-systems', '1.1.3 Embedded Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dedicated hardware”?", "options": ["A medical embedded system dedicated to regulating a heartbeat", "A computer that can run any software and perform many different tasks", "Software stored permanently in ROM that the user normally cannot change", "Components and a microprocessor reserved for this one system only"]}'::jsonb, '{"answer": 3, "explain": "“Dedicated hardware” means: Components and a microprocessor reserved for this one system only"}'::jsonb),
